function toACE(domainName) {
  // Handle possible trailing dot
  const hasTrailingDot = domainName.endsWith('.');
  const core = hasTrailingDot ? domainName.slice(0, -1) : domainName;

  // Split into labels and convert each label
  const labels = core.split('.').filter(l => l.length > 0);
  const aceLabels = labels.map(label => {
    // punycode.toASCII expects a single label
    return punycode.toASCII(label);
