function createSecureTlsStreamPair(options = {}) {
  const {
    // Optional: provide your own CA/cert/key material
    ca,
    serverCert,
    serverKey,
    clientCert,
    clientKey,

    // Optional: if you want to use a specific SNI/hostname for verification
    serverName = 'localhost',

    // Optional: TLS options
    minVersion = 'TLSv1.2',
    maxVersion,

    // Optional: ALPN protocols
    ALPNProtocols,

    // Optional: whether to require client cert on server side
    requestClientCert = false,
    rejectUnauthorized = true,

    // Optional: session resumption
    enableSessionTickets = true,

    // Optional: handshake timeout (ms)
    handshakeTimeoutMs = 10000,

    // Optional: cipher suites
    ciphers,

    // Optional: debug hooks
    onServerSecure,
    onClientSecure
  } = options;

  // Generate ephemeral self-signed certs if not provided
  function ensurePemMaterial() {
    if (serverCert && serverKey) return;

    // Minimal self-signed cert generation using crypto + openssl is not available in pure Node.
    // So we require caller-provided PEMs for real security.
    // However, to keep the function usable, we can create a "secure" pair only if PEMs are provided.
    // If not provided, throw a clear error.
    throw new Error(
      'Missing TLS material. Provide serverCert/serverKey (PEM) and optionally clientCert/clientKey/ca.'
    );
  }

  ensurePemMaterial();

  const serverTLSOptions = {
    isServer: true,
    ca: ca || undefined,
    cert: serverCert,
    key: serverKey,
    requestCert: !!requestClientCert,
    rejectUnauthorized: !!rejectUnauthorized,
    minVersion,
    maxVersion,
    ALPNProtocols,
    ciphers,
    honorCipherOrder: true,
    enableTrace: false,
    enableSessionTickets: enableSessionTickets !== false
  };

  if (clientCert && clientKey) {
    serverTLSOptions.crl = undefined;
    serverTLSOptions.cert = serverCert;
    serverTLSOptions.key = serverKey;
    // requestCert controls whether server asks for client cert; if true, provide CA to verify.
    // If caller wants mTLS, they should provide ca and set requestClientCert=true.
  }

  const clientTLSOptions = {
    isServer: false,
    ca: ca || undefined,
    cert: clientCert || undefined,
    key: clientKey || undefined,
    servername: serverName,
    rejectUnauthorized: !!rejectUnauthorized,
    minVersion,
    maxVersion,
    ALPNProtocols,
    ciphers,
    honorCipherOrder: true,
    enableTrace: false,
    enableSessionTickets: enableSessionTickets !== false
  };

  // Create a local TCP connection pair to connect the TLS server and TLS client.
  // Then expose:
  //  - encrypted channel: the raw TCP sockets (ciphertext on the wire)
  //  - cleartext channel: the TLS streams (plaintext after decryption/encryption)
  const server = net.createServer({ allowHalfOpen: true });

  let encryptedClientSocket;
  let encryptedServerSocket;

  const encryptedChannel = {
    clientSocket: null,
    serverSocket: null
  };

  const cleartextChannel = {
    clientTLS: null,
    serverTLS: null
  };

  const serverReady = new Promise((resolve, reject) => {
    server.on('error', reject);
    server.listen(0, '127.0.0.1', () => resolve());
  });

  const pairReady = new Promise((resolve, reject) => {
    let resolved = false;

    const cleanup = (err) => {
      if (resolved) return;
      resolved = true;
      try { server.close(); } catch (_) {}
      if (encryptedClientSocket) encryptedClientSocket.destroy();
      if (encryptedServerSocket) encryptedServerSocket.destroy();
      if (cleartextChannel.clientTLS) cleartextChannel.clientTLS.destroy();
      if (cleartextChannel.serverTLS) cleartextChannel.serverTLS.destroy();
      reject(err);
    };

    const timeout = setTimeout(() => {
      cleanup(new Error('TLS handshake timed out'));
    }, handshakeTimeoutMs);

    server.once('connection', (sock) => {
      encryptedServerSocket = sock;
      encryptedChannel.serverSocket = sock;

      const serverTLS = tls.connect; // placeholder to avoid lint; will be overwritten below
      // Actually create TLS server over the accepted socket:
      const serverTLSServer = new tls.TLSSocket(encryptedServerSocket, serverTLSOptions);

      cleartextChannel.serverTLS = serverTLSServer;

      serverTLSServer.once('secureConnect', () => {
        if (typeof onServerSecure === 'function') onServerSecure(serverTLSServer);
      });

      serverTLSServer.once('error', (e) => cleanup(e));

      // Create client TLS over a new connection to the server
      const clientSock = net.connect(server.address().port, '127.0.0.1');
      encryptedClientSocket = clientSock;
      encryptedChannel.clientSocket = clientSock;

      clientSock.once('error', (e) => cleanup(e));

      const clientTLS = new tls.TLSSocket(clientSock, clientTLSOptions);
      cleartextChannel.clientTLS = clientTLS;

      clientTLS.once('secureConnect', () => {
        if (typeof onClientSecure === 'function') onClientSecure(clientTLS);
      });

      clientTLS.once('error', (e) => cleanup(e));

      let serverSecure = false;
      let clientSecure = false;

      const maybeResolve = () => {
        if (serverSecure && clientSecure && !resolved) {
          resolved = true;
          clearTimeout(timeout);
          try { server.close(); } catch (_) {}
          resolve({
            encryptedChannel,
            cleartextChannel
          });
        }
      };

      serverTLSServer.once('secureConnect', () => {
        serverSecure = true;
        maybeResolve();
      });

      clientTLS.once('secureConnect', () => {
        clientSecure = true;
        maybeResolve();
      });
    });

    serverReady.catch(cleanup);
  });

  return pairReady;
}

