function parseTlsSubject(subject) {
  if (subject == null) return {};
  const str = String(subject).trim();
  if (!str) return {};

  const result = {};
  const parts = str.split('/').filter(Boolean);

  for (const part of parts) {
    const idx = part.indexOf('=');
    if (idx === -1) continue;

    const key = part.slice(0, idx).trim();
    const value = part.slice(idx + 1).trim();

    if (!key) continue;

    if (Object.prototype.hasOwnProperty.call(result, key)) {
      if (Array.isArray(result[key])) result[key].push(value);
      else result[key] = [result[key], value];
    } else {
      result[key] = value;
    }
  }

  return result;
}

function normalizeAbsoluteUrl(inputUrl) {
  if (typeof inputUrl !== 'string') throw new TypeError('inputUrl must be a string');

  const url = new URL(inputUrl);

  // Ensure protocol + host + path + query are preserved.
  // Normalize path by removing redundant trailing slash (except root).
  let pathname = url.pathname || '/';
  if (pathname.length > 1 && pathname.endsWith('/')) pathname = pathname.slice(0, -1);

  // Preserve query exactly as provided (URL normalizes ordering; keep as is).
  const query = url.search || '';

  return `${url.protocol}//${url.host}${pathname}${query}`;
}

const factorial = function(n) {
